package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.cascades.join;

import org.eclipse.rdf4j.common.annotation.Experimental;

/**
 * A selectivity represented without prematurely exponentiating a multiplicative estimate.
 * <p>
 * Exact zero and unavailable evidence are deliberately distinct: an exact zero proves an empty result, while
 * unavailable evidence must be surfaced to the caller and resolved by its statistics fallback.
 */
@Experimental
public record LogSelectivity(Kind kind, double logValue) {

	public enum Kind {
		EXACT_ZERO,
		POSITIVE,
		UNAVAILABLE
	}

	private static final LogSelectivity EXACT_ZERO = new LogSelectivity(Kind.EXACT_ZERO,
			Double.NEGATIVE_INFINITY);
	private static final LogSelectivity UNAVAILABLE = new LogSelectivity(Kind.UNAVAILABLE, Double.NaN);

	public LogSelectivity {
		if (kind == null) {
			throw new NullPointerException("kind");
		}
		switch (kind) {
		case EXACT_ZERO -> {
			if (logValue != Double.NEGATIVE_INFINITY) {
				throw new IllegalArgumentException("exact-zero selectivity requires negative-infinity log value");
			}
		}
		case POSITIVE -> {
			if (!Double.isFinite(logValue)) {
				throw new IllegalArgumentException("positive selectivity requires a finite log value: " + logValue);
			}
		}
		case UNAVAILABLE -> {
			if (!Double.isNaN(logValue)) {
				throw new IllegalArgumentException("unavailable selectivity requires a NaN log value");
			}
		}
		}
	}

	public static LogSelectivity fromLinear(double selectivity) {
		if (Double.isNaN(selectivity) || Double.isInfinite(selectivity) || selectivity < 0.0d) {
			return unavailable();
		}
		if (selectivity == 0.0d) {
			return exactZero();
		}
		return positiveLog(Math.log(selectivity));
	}

	public static LogSelectivity positiveLog(double logValue) {
		return Double.isFinite(logValue) ? new LogSelectivity(Kind.POSITIVE, logValue) : unavailable();
	}

	public static LogSelectivity exactZero() {
		return EXACT_ZERO;
	}

	public static LogSelectivity unavailable() {
		return UNAVAILABLE;
	}

	public boolean isExactZero() {
		return kind == Kind.EXACT_ZERO;
	}

	public boolean isPositive() {
		return kind == Kind.POSITIVE;
	}

	public boolean isUnavailable() {
		return kind == Kind.UNAVAILABLE;
	}

	/** Selectivity inputs are probabilities; cap estimator overshoot without imposing a positive lower floor. */
	public LogSelectivity cappedAtOne() {
		return isPositive() && logValue > 0.0d ? new LogSelectivity(Kind.POSITIVE, 0.0d) : this;
	}

	public double linearValue() {
		if (isExactZero()) {
			return 0.0d;
		}
		if (isUnavailable()) {
			return Double.NaN;
		}
		return JoinCardinalityModel.saturatedExp(logValue);
	}

	/**
	 * Geometric mean in log space. One unavailable direction yields the available direction; two unavailable directions
	 * remain explicitly unavailable.
	 */
	public static LogSelectivity geometricMean(LogSelectivity forward, LogSelectivity backward) {
		if (forward == null || forward.isUnavailable()) {
			return backward == null ? unavailable() : backward;
		}
		if (backward == null || backward.isUnavailable()) {
			return forward;
		}
		if (forward.isExactZero() || backward.isExactZero()) {
			return exactZero();
		}
		return positiveLog((forward.logValue + backward.logValue) * 0.5d);
	}
}
